}

function buildRequestMaterials(task, featureId) {
  const materials = [
    {
      material_id: `material-feature-${featureId}`,
      material_type: 'feature_id',
      source_value: featureId,
      role: 'primary_feature',
      must_read: true,
      must_summarize: false,
